import { ReactElement } from 'react';

interface TempoCanvasConfig {
    name: string;
    /** Canvas surface background color (any CSS color string, e.g. `#232323`).
     *  Optional — unset means the renderer uses its default background. */
    backgroundColor?: string;
}
/** @deprecated Renamed to {@link TempoCanvasConfig}. Kept as an alias for
 *  backwards compatibility with canvas files authored against older SDKs. */
type TempoPage = TempoCanvasConfig;
interface StoryboardLayout {
    x: number;
    y: number;
    width: number;
    height: number;
    zIndex?: number;
    intrinsicSizing?: "root-element";
}
interface TempoStoryboard {
    render: () => ReactElement;
    name?: string;
    layout: StoryboardLayout;
}
interface TempoRouteStoryboard {
    route: string;
    name?: string;
    layout: StoryboardLayout;
}
interface TempoHtmlStoryboard {
    filepath: string;
    name?: string;
    layout: StoryboardLayout;
}

export type { StoryboardLayout as S, TempoCanvasConfig as T, TempoHtmlStoryboard as a, TempoPage as b, TempoRouteStoryboard as c, TempoStoryboard as d };
